-- SQLD 제54회 기출 복원 — 50문항 일괄 적재
-- mock_exam: kind=PAST_EXAM, visibility=PUBLISHED, expert_verified=0

SET @sqld_seq := (SELECT COALESCE(MAX(sequence), 0) + 1 FROM mock_exam WHERE exam_type = 'SQLD');

INSERT INTO mock_exam
  (name, exam_type, sequence, visibility, expert_verified,
   kind, exam_year, exam_round, exam_date, created_at, updated_at)
VALUES
  ('SQLD 제54회 기출 복원', 'SQLD', @sqld_seq, 'PUBLISHED', 0,
   'PAST_EXAM', 2024, 54, '2024-08-24', NOW(6), NOW(6));

SET @mock_exam_id := LAST_INSERT_ID();

INSERT INTO question
  (subject_id, content, question_type, correct_option, explanation,
   topic, difficulty, mock_exam_id, display_order,
   verification_category, content_hash, created_at, updated_at)
VALUES
  (3, '아래 설명으로 알맞은 데이터 모델링 단계는?\n\n**<지문>**\n시스템으로 구축하고자 하는 업무에 대해 Key, 속성, 관계 등을 정확하게 표현하고 재사용성이 높은 모델링이다.\n\n① 논리적 데이터 모델링\n② 개념적 데이터 모델링\n③ 물리적 데이터 모델링\n④ 데이터베이스 모델링', 'MCQ', 1, '정답: 1. 논리적 데이터 모델링은 업무에서 필요한 데이터의 키, 속성, 관계를 구체적으로 표현하고 재사용성이 높은 데이터 구조를 만드는 단계이다.\n\n**오답 풀이**\n- 1번: 업무 데이터의 키, 속성, 관계를 논리적으로 정리하는 단계이므로 적절하다.\n- 2번: 개념적 데이터 모델링은 핵심 엔터티와 관계를 높은 추상화 수준에서 파악하는 단계이다.\n- 3번: 물리적 데이터 모델링은 DBMS, 인덱스, 저장 구조 등 물리 구현을 고려하는 단계이다.\n- 4번: 데이터베이스 모델링은 포괄적 표현이며 단계 명칭으로는 부정확하다.\n\n**보충 개념**\n개념 모델링은 업무 개념을 추상화하고, 논리 모델링은 속성·식별자·관계를 구체화한다. 물리 모델링은 실제 DBMS 구현 구조로 변환하는 단계이다.',
   '논리적 데이터 모델링', 2, @mock_exam_id, 1, 'NONE', NULL, NOW(6), NOW(6)),
  (3, '엔터티 특징으로 적절하지 않은 것은?\n\n① 엔터티는 고유한 식별자를 가진다.\n② 엔터티는 데이터 저장의 기본 단위이다.\n③ 엔터티는 반드시 속성을 가진다.\n④ 속성이 없는 엔터티가 있을 수 있다.', 'MCQ', 4, '정답: 4. 엔터티는 업무상 관리해야 하는 대상이며, 이를 설명하는 속성을 가져야 한다.\n\n**오답 풀이**\n- 1번: 엔터티는 인스턴스를 식별할 수 있는 식별자를 가져야 한다.\n- 2번: 엔터티는 업무 데이터를 저장하고 관리하는 기본 단위이다.\n- 3번: 엔터티는 하나 이상의 속성을 가져야 한다.\n- 4번: 속성이 없는 엔터티는 관리할 데이터가 없으므로 부적절하다.\n\n**보충 개념**\n엔터티는 업무에서 독립적으로 식별 가능한 대상이다. 엔터티는 인스턴스의 집합이며, 각 인스턴스는 속성값을 가진다.',
   '엔터티 특징', 1, @mock_exam_id, 2, 'NONE', NULL, NOW(6), NOW(6)),
  (3, '속성 특징으로 적절하지 않은 것은?\n\n① 속성은 엔터티의 특성을 나타낸다.\n② 속성에는 기본 속성과 파생 속성이 있다.\n③ 파생 속성은 다른 속성에서 계산된다.\n④ 파생 속성은 많을수록 좋다.', 'MCQ', 4, '정답: 4. 파생 속성은 계산으로 얻을 수 있으므로 무분별하게 많을수록 좋은 것이 아니라 중복과 정합성 문제를 고려해야 한다.\n\n**오답 풀이**\n- 1번: 속성은 엔터티 인스턴스를 설명하는 항목이다.\n- 2번: 속성은 기본 속성, 설계 속성, 파생 속성 등으로 분류할 수 있다.\n- 3번: 파생 속성은 다른 속성으로부터 계산되거나 변형되어 생성된다.\n- 4번: 파생 속성이 많으면 데이터 중복과 갱신 불일치가 발생할 수 있다.\n\n**보충 개념**\n파생 속성은 조회 성능이나 편의성을 위해 둘 수 있지만, 원천 속성과 값이 불일치하지 않도록 관리해야 한다.',
   '파생 속성', 1, @mock_exam_id, 3, 'NONE', NULL, NOW(6), NOW(6)),
  (3, '식별자의 특징으로 적절하지 않은 것은?\n\n① 식별자는 엔터티의 유일성을 보장한다.\n② 식별자는 최소성 조건을 만족해야 한다.\n③ 주식별자는 엔터티를 고유하게 식별한다.\n④ 주식별자의 값은 자주 변경될 수 있다.', 'MCQ', 4, '정답: 4. 주식별자는 인스턴스를 안정적으로 식별해야 하므로 자주 변경되는 값은 적절하지 않다.\n\n**오답 풀이**\n- 1번: 식별자는 인스턴스를 유일하게 구분한다.\n- 2번: 식별자는 유일성을 만족하는 최소 속성 집합이어야 한다.\n- 3번: 주식별자는 엔터티의 대표 식별자이다.\n- 4번: 주식별자는 안정성을 가져야 하므로 값 변경이 잦으면 부적절하다.\n\n**보충 개념**\n주식별자의 특징은 유일성, 최소성, 불변성, 존재성이다. 자주 바뀌는 속성은 주식별자 후보로 적합하지 않다.',
   '식별자 특징', 1, @mock_exam_id, 4, 'NONE', NULL, NOW(6), NOW(6)),
  (3, '식별자 관계에 대한 설명으로 적절하지 않은 것은?\n\n① 식별자 관계는 부모 엔터티와 종속적인 관계를 맺는다.\n② 비식별자 관계에서 부모와의 관계는 항상 필수 조건이다.\n③ 식별자 관계는 부모의 식별자를 자식에게 전달한다.\n④ 비식별자 관계는 자식 엔터티가 독립적으로 존재할 수 있다.', 'MCQ', 2, '정답: 2. 비식별자 관계는 부모 식별자가 자식의 일반 속성 또는 외래키로 포함되는 관계이며, 부모와의 참여가 항상 필수인 것은 아니다.\n\n**오답 풀이**\n- 1번: 식별자 관계에서는 자식이 부모에 존재 종속적인 경우가 많다.\n- 2번: 비식별자 관계도 선택 관계가 가능하므로 항상 필수라고 할 수 없다.\n- 3번: 식별자 관계에서는 부모 식별자가 자식 주식별자에 포함된다.\n- 4번: 비식별자 관계에서는 자식이 자체 식별자를 가지고 독립성이 커질 수 있다.\n\n**보충 개념**\n식별자 관계는 부모의 식별자가 자식의 주식별자 일부가 되는 관계이다. 비식별자 관계는 부모의 식별자가 자식의 일반 외래키로 존재한다.',
   '식별자 관계', 2, @mock_exam_id, 5, 'NONE', NULL, NOW(6), NOW(6)),
  (3, '아래 고객, 주문 관련 ERD에 대한 설명으로 적절한 것은?\n\n**<ERD>**\n고객(고객번호, 고객명) 1 : N 주문(주문번호, 고객번호(FK))\n\n주문의 고객번호는 고객 엔터티의 고객번호를 참조한다.\n\n① 주문에서의 고객번호는 고객 엔터티에서 상속받은 것이다.\n② 고객은 주문 엔터티의 자식 엔터티이다.\n③ 주문번호는 고객 엔터티에서 상속받은 식별자이다.\n④ 고객과 주문은 서로 아무 관계가 없다.', 'MCQ', 1, '정답: 1. 주문 엔터티의 고객번호는 고객 엔터티의 식별자를 참조하는 외래키로 볼 수 있다.\n\n**오답 풀이**\n- 1번: 주문의 고객번호는 고객의 고객번호를 참조하므로 적절하다.\n- 2번: 일반적으로 주문이 고객의 자식 엔터티이다.\n- 3번: 주문번호는 주문 자체를 식별하는 속성이다.\n- 4번: 고객과 주문은 1:N 관계를 가질 수 있다.\n\n**보충 개념**\n부모 엔터티의 식별자는 관계를 통해 자식 엔터티에 외래키로 전달될 수 있다. 식별자 관계인지 비식별자 관계인지에 따라 자식의 주식별자 포함 여부가 달라진다.',
   '외래키', 2, @mock_exam_id, 6, 'NONE', NULL, NOW(6), NOW(6)),
  (4, '함수 종속성에 대한 설명으로 가장 적절한 것은?\n\n① 일반 속성이 주식별자 전체에 함수 종속된 상태는 제2정규형의 조건과 관련된다.\n② 일반 속성이 주식별자 일부에만 종속되면 제2정규형을 만족한다.\n③ 상품번호에 상품명이 종속되는 관계는 상품명이 상품번호를 결정한다는 뜻이다.\n④ 함수 종속성은 정규화와 관련이 없다.', 'MCQ', 1, '정답: 1. 제2정규형은 제1정규형을 만족하면서 일반 속성이 복합 주식별자 전체에 완전 함수 종속되어야 한다.\n\n**오답 풀이**\n- 1번: 완전 함수 종속은 제2정규형과 관련된다.\n- 2번: 일부 식별자에만 종속되는 것은 부분 함수 종속으로 제2정규형 위반이다.\n- 3번: 상품번호에 상품명이 종속된다는 것은 상품번호가 상품명을 결정한다는 뜻이다.\n- 4번: 함수 종속성은 정규화의 핵심 판단 기준이다.\n\n**보충 개념**\n함수 종속은 X 값이 정해지면 Y 값이 하나로 정해지는 관계이다. 정규화는 부분 함수 종속과 이행 함수 종속을 제거하여 이상 현상을 줄인다.',
   '함수 종속성', 2, @mock_exam_id, 7, 'NONE', NULL, NOW(6), NOW(6)),
  (3, '아래의 경우 생성하는 식별자는?\n\n**<지문>**\n업무적으로 만들어지지는 않지만 원조식별자가 복잡한 구성을 갖고 있기 때문에 인위적으로 만든 식별자\n\n① 외래키\n② 복합 식별자\n③ 인조 식별자\n④ 자연 식별자', 'MCQ', 3, '정답: 3. 업무 식별자가 복잡하거나 부적절할 때 설계자가 인위적으로 만든 식별자는 인조 식별자이다.\n\n**오답 풀이**\n- 1번: 외래키는 다른 엔터티를 참조하기 위해 전달받은 식별자이다.\n- 2번: 복합 식별자는 둘 이상의 속성으로 구성된 식별자이다.\n- 3번: 인위적으로 만든 식별자이므로 정답이다.\n- 4번: 자연 식별자는 업무적으로 자연스럽게 존재하는 식별자이다.\n\n**보충 개념**\n인조 식별자는 편리하지만 업무 의미를 직접 담지 않는다. 인조 식별자를 사용하더라도 업무상 유일성 제약은 별도로 고려해야 한다.',
   '인조 식별자', 1, @mock_exam_id, 8, 'NONE', NULL, NOW(6), NOW(6)),
  (3, '관계 표기법에 대한 설명으로 적절하지 않은 것은?\n\n① IE 표기법에서는 관계의 필수 여부를 선과 기호로 표현할 수 있다.\n② 바커 표기법에서는 관계의 선택성을 표시할 수 있다.\n③ IE 표기법의 실선과 바커 표기법의 O 표시는 같은 의미로 항상 대응된다.\n④ 관계 표기법은 엔터티 간 참여도와 관계 수를 표현하는 데 사용된다.', 'MCQ', 3, '정답: 3. IE 표기법과 바커 표기법은 관계의 선택성, 필수성, 식별성을 표현하는 방식이 다르므로 특정 기호를 단순히 같은 의미로 항상 대응시키면 안 된다.\n\n**오답 풀이**\n- 1번: IE 표기법은 관계의 선택성과 카디널리티를 기호로 표현한다.\n- 2번: 바커 표기법도 관계 선택성과 필수성을 표현할 수 있다.\n- 3번: 서로 다른 표기법의 기호를 단순 대응시키는 설명은 부적절하다.\n- 4번: 관계 표기법은 엔터티 간 관계 구조를 표현하는 데 사용된다.\n\n**보충 개념**\nERD 표기법은 바커 표기법, IE 표기법 등 여러 방식이 있다. 표기법마다 선택 관계, 필수 관계, 식별 관계를 표현하는 기호가 다르므로 해석 기준을 구분해야 한다.',
   'ERD 표기법', 3, @mock_exam_id, 9, 'NONE', NULL, NOW(6), NOW(6)),
  (5, 'NULL에 대한 설명으로 적절한 것은?\n\n① NULL에는 일반 비교 연산자를 사용해 항상 TRUE 또는 FALSE를 얻을 수 있다.\n② 바커 표기법에서는 NULL 허용 여부를 알 수 없다.\n③ NULL은 미지의 값으로 일반 비교 연산으로는 비교 결과를 확정하기 어렵다.\n④ IE 표기법에서 NULL 허용 여부를 알 수 있다.', 'MCQ', 3, '정답: 3. NULL은 알 수 없거나 존재하지 않는 값을 의미하며, 일반 비교 연산의 결과가 UNKNOWN이 될 수 있다.\n\n**오답 풀이**\n- 1번: NULL 비교 결과는 TRUE/FALSE가 아니라 UNKNOWN이 될 수 있다.\n- 2번: 표기법에 대한 설명보다 NULL의 본질적 설명으로는 부적절하다.\n- 3번: NULL의 의미와 비교 특성을 가장 정확히 설명한다.\n- 4번: 표기법 설명은 일반적인 NULL 연산 설명으로 보기 어렵다.\n\n**보충 개념**\nNULL 여부는 `= NULL`이 아니라 `IS NULL` 또는 `IS NOT NULL`로 판단한다. WHERE 절은 TRUE인 행만 반환하므로 UNKNOWN은 결과에서 제외된다.',
   'NULL', 2, @mock_exam_id, 10, 'NONE', NULL, NOW(6), NOW(6)),
  (7, 'CTAS에 대한 설명으로 적절하지 않은 것은?\n\n① SELECT 결과를 기반으로 새 테이블을 만들 수 있다.\n② 제약조건이 모두 복사된다.\n③ 기존 테이블의 구조를 기반으로 한다.\n④ 일부 제약조건은 별도로 추가할 수 있다.', 'MCQ', 2, '정답: 2. CTAS는 조회 결과를 기반으로 테이블을 생성하지만 기본키, 외래키, CHECK, DEFAULT 등의 제약조건이 모두 복사되는 것은 아니다.\n\n**오답 풀이**\n- 1번: CTAS는 SELECT 결과로 새 테이블을 생성한다.\n- 2번: 제약조건이 모두 복사된다는 설명은 틀리다.\n- 3번: 조회 대상 컬럼의 구조를 기반으로 테이블이 생성된다.\n- 4번: 필요한 제약조건은 생성 후 별도로 추가할 수 있다.\n\n**보충 개념**\nCTAS는 빠르게 테이블과 데이터를 복제할 때 사용한다. 그러나 인덱스, 제약조건, 트리거 등은 별도로 생성해야 하는 경우가 많다.',
   'CTAS', 2, @mock_exam_id, 11, 'NONE', NULL, NOW(6), NOW(6)),
  (6, 'View에 대한 설명으로 적절하지 않은 것은?\n\n① View는 조회 속도를 높이기 위해 사용된다.\n② View는 일반적으로 실제 데이터를 저장하지 않는다.\n③ 기본 테이블의 컬럼이 추가되어도 View를 통해 응용 프로그램에 미치는 영향을 줄일 수 있다.\n④ View는 다른 테이블의 데이터를 참조한다.', 'MCQ', 1, '정답: 1. 일반 View는 SQL을 저장한 논리적 객체에 가까우며, 조회 속도를 높이는 것이 주된 목적이라고 보기 어렵다.\n\n**오답 풀이**\n- 1번: 일반 View는 조회 편의성, 보안, 독립성 제공 목적이 크며 속도 향상이 보장되지 않는다.\n- 2번: 일반 View는 실제 데이터를 저장하지 않고 기본 테이블을 참조한다.\n- 3번: View를 통해 응용 프로그램이 기본 테이블 구조 변경의 영향을 덜 받을 수 있다.\n- 4번: View는 기본 테이블 또는 다른 View의 데이터를 참조할 수 있다.\n\n**보충 개념**\nView는 논리적 테이블처럼 사용할 수 있는 객체이다. 보안, SQL 단순화, 논리적 데이터 독립성 제공에 활용된다.',
   'VIEW', 2, @mock_exam_id, 12, 'NONE', NULL, NOW(6), NOW(6)),
  (5, 'Database의 논리적 업무 최소 단위는?\n\n① 트랜잭션\n② 레코드\n③ Query\n④ 테이블', 'MCQ', 1, '정답: 1. 트랜잭션은 데이터베이스에서 더 이상 분할할 수 없는 논리적 업무 처리 단위이다.\n\n**오답 풀이**\n- 1번: 논리적 업무 최소 단위로 적절하다.\n- 2번: 레코드는 테이블의 한 행을 의미한다.\n- 3번: Query는 트랜잭션을 구성하는 개별 SQL 문일 수 있지만 논리적 업무 단위로 보기 어렵다.\n- 4번: 테이블은 데이터를 저장하는 구조이다.\n\n**보충 개념**\n트랜잭션은 여러 SQL 문을 하나의 논리적 단위로 묶을 수 있다. 트랜잭션은 ACID 특성을 만족해야 한다.',
   '트랜잭션', 1, @mock_exam_id, 13, 'NONE', NULL, NOW(6), NOW(6)),
  (5, '아래 정규표현식 조건에 해당하지 않는 전화번호 형식으로 가장 적절한 것은?\n\n**<조건>**\n전화번호는 숫자와 하이픈으로 구성되며, 지역번호가 `02`로 시작하는 형태를 검사한다.\n\n① 02-123-4567\n② 02-1234-5678\n③ 031-123-4567\n④ 02-9876-5432', 'MCQ', 3, '정답: 3. 조건은 `02`로 시작하는 전화번호 형태이므로 `031-123-4567`은 해당 조건에 맞지 않는다.\n\n**오답 풀이**\n- 1번: 02로 시작하는 전화번호 형식이다.\n- 2번: 02로 시작하는 전화번호 형식이다.\n- 3번: 031로 시작하므로 02 시작 조건에 맞지 않는다.\n- 4번: 02로 시작하는 전화번호 형식이다.\n\n**보충 개념**\n정규표현식에서 `^02`는 문자열이 02로 시작함을 의미한다. 하이픈과 숫자 개수 조건이 함께 제시되면 각 자리수를 정확히 확인해야 한다.',
   '정규표현식', 3, @mock_exam_id, 14, 'NONE', NULL, NOW(6), NOW(6)),
  (6, '아래의 계층형 쿼리에 대한 설명으로 적절하지 않은 것은?\n\n```sql\nSELECT emp_no, mgr_no\nFROM emp\nSTART WITH mgr_no IS NULL\nCONNECT BY PRIOR emp_no = mgr_no;\n```\n\n**<조건>**\nemp_no는 하위 사원 번호, mgr_no는 상위 관리자 번호를 나타낸다.\n\n① 계층 구조를 조회한다.\n② 상위 관리자부터 조회한다.\n③ 역방향 탐색이다.\n④ 순방향 탐색이다.', 'MCQ', 3, '정답: 3. `CONNECT BY PRIOR emp_no = mgr_no`는 부모 행의 emp_no가 자식 행의 mgr_no와 같은 행을 찾아 내려가는 순방향 계층 탐색이다.\n\n**오답 풀이**\n- 1번: CONNECT BY를 사용하므로 계층 구조를 조회한다.\n- 2번: START WITH mgr_no IS NULL이면 최상위 관리자부터 시작한다.\n- 3번: 역방향이라는 설명은 틀리다.\n- 4번: 부모에서 자식으로 내려가는 순방향이다.\n\n**보충 개념**\n계층형 쿼리에서 PRIOR의 위치가 탐색 방향을 결정한다. `PRIOR 부모컬럼 = 자식컬럼`은 일반적으로 하위 방향 탐색이다.',
   '계층형 쿼리', 3, @mock_exam_id, 15, 'NONE', NULL, NOW(6), NOW(6)),
  (6, '서브쿼리에 대한 설명으로 적절하지 않은 것은?\n\n① 서브쿼리는 메인쿼리 안에서 사용되는 또 다른 SELECT 문이다.\n② 서브쿼리의 내부 컬럼은 메인쿼리에서 항상 직접 참조할 수 있다.\n③ 상관 서브쿼리는 메인쿼리의 컬럼을 참조할 수 있다.\n④ 인라인 뷰는 FROM 절에서 사용되는 서브쿼리이다.', 'MCQ', 2, '정답: 2. 서브쿼리 내부에서만 정의된 컬럼은 일반적으로 메인쿼리에서 직접 참조할 수 없으며, 인라인 뷰처럼 FROM 절에 별칭을 부여한 경우에만 그 결과 컬럼을 참조할 수 있다.\n\n**오답 풀이**\n- 1번: 서브쿼리의 기본 설명이다.\n- 2번: 서브쿼리 내부 컬럼을 항상 직접 참조할 수 있다는 설명은 틀리다.\n- 3번: 상관 서브쿼리는 메인쿼리의 컬럼을 참조한다.\n- 4번: FROM 절의 서브쿼리는 인라인 뷰라고 부른다.\n\n**보충 개념**\n서브쿼리는 SELECT, FROM, WHERE 등 여러 절에서 사용할 수 있다. 사용 위치에 따라 스칼라 서브쿼리, 인라인 뷰, 중첩 서브쿼리 등으로 구분된다.',
   '서브쿼리', 3, @mock_exam_id, 16, 'NONE', NULL, NOW(6), NOW(6)),
  (5, '아래 CASE 표현식과 같은 결과를 반환하는 함수로 가장 적절한 것은?\n\n```sql\nCASE\n  WHEN col1 = ''X'' THEN NULL\n  ELSE col1\nEND\n```\n\n① NVL(col1, ''X'')\n② NULLIF(col1, ''X'')\n③ COALESCE(col1, ''X'')\n④ NVL2(col1, NULL, ''X'')', 'MCQ', 2, '정답: 2. NULLIF(col1, ''X'')는 col1과 ''X''가 같으면 NULL을 반환하고, 다르면 col1을 반환한다.\n\n**오답 풀이**\n- 1번: NVL은 col1이 NULL이면 대체값을 반환한다.\n- 2번: CASE 표현식과 같은 의미이다.\n- 3번: COALESCE는 첫 번째 NULL이 아닌 값을 반환한다.\n- 4번: NVL2는 첫 번째 인자의 NULL 여부에 따라 두 번째 또는 세 번째 인자를 반환한다.\n\n**보충 개념**\nNULLIF(expr1, expr2)는 두 값이 같으면 NULL, 다르면 expr1을 반환한다. 특정 값과 같을 때 NULL로 바꾸는 경우 유용하다.',
   'NULLIF', 2, @mock_exam_id, 17, 'NONE', NULL, NOW(6), NOW(6)),
  (5, '다음 SQL 중 Oracle 기준으로 결과가 다른 것은?\n\n**<TAB>**\n| COL1 | COL2 | COL3 |\n|---:|---:|---|\n| 1 | 2 | A |\n| 2 | 3 | B |\n| 3 | 2 | C |\n| 4 | 3 | D |\n\n① SELECT COL1, COL2, COL3 FROM TAB WHERE COL1 < 5\n② SELECT T.* FROM TAB AS T\n③ SELECT * FROM TAB\n④ SELECT * FROM TAB WHERE COL2 IN (2, 3)', 'MCQ', 2, '정답: 2. Oracle에서는 FROM 절의 테이블 별칭에 AS 키워드를 사용할 수 없으므로 `SELECT T.* FROM TAB AS T`는 오류가 발생한다.\n\n**오답 풀이**\n- 1번: COL1이 모두 5보다 작으므로 전체 행이 조회된다.\n- 2번: Oracle 기준 테이블 별칭에 AS를 사용해 문법 오류가 발생한다.\n- 3번: 전체 행이 조회된다.\n- 4번: COL2가 2 또는 3인 전체 행이 조회된다.\n\n**보충 개념**\nOracle에서는 컬럼 별칭에는 AS를 사용할 수 있지만, 테이블 별칭에는 일반적으로 AS를 쓰지 않는다. `FROM TAB T`처럼 작성한다.',
   '테이블 별칭', 3, @mock_exam_id, 18, 'NONE', NULL, NOW(6), NOW(6)),
  (6, 'STADIUM 컬럼이 두 개 테이블에 모두 존재하는 조인 SQL에 대한 설명으로 적절하지 않은 것은?\n\n① 두 테이블에 같은 컬럼명이 있으면 컬럼명 앞에 테이블명 또는 별칭을 붙여 구분해야 한다.\n② SELECT 절에서 STADIUM을 사용할 때 모호하면 테이블 별칭을 명시해야 한다.\n③ 동일한 이름의 컬럼이 여러 테이블에 존재해도 항상 컬럼명만 단독으로 사용할 수 있다.\n④ 조인 SQL에서는 컬럼 소속을 명확히 작성하는 것이 좋다.', 'MCQ', 3, '정답: 3. 조인 대상 테이블에 동일한 컬럼명이 있으면 컬럼명만 단독으로 사용했을 때 모호한 컬럼 오류가 발생할 수 있다.\n\n**오답 풀이**\n- 1번: 모호한 컬럼은 테이블명 또는 별칭으로 구분해야 한다.\n- 2번: SELECT 절에서도 모호한 컬럼은 별칭을 붙여야 한다.\n- 3번: 항상 단독 사용 가능하다는 설명은 틀리다.\n- 4번: 조인 SQL에서는 명시적 컬럼 참조가 가독성과 정확성을 높인다.\n\n**보충 개념**\n여러 테이블을 조인할 때 같은 이름의 컬럼이 존재하면 `A.STADIUM`, `B.STADIUM`처럼 소속을 명확히 해야 한다.',
   '조인 컬럼', 2, @mock_exam_id, 19, 'NONE', NULL, NOW(6), NOW(6)),
  (5, '아래 SQL에 대한 결과 설명으로 가장 적절한 것은?\n\n```sql\nSELECT COALESCE(A, 50 * B, ''50'') AS RESULT\nFROM T;\n```\n\n① B가 NULL이 아니면 항상 B 값을 반환한다.\n② A와 B가 NULL일 경우 100을 반환한다.\n③ A가 NULL일 경우에는 언제나 50 * B를 반환한다.\n④ A가 NULL이 아닐 경우 A 값을 반환한다.', 'MCQ', 4, '정답: 4. COALESCE는 왼쪽부터 검사하여 첫 번째 NULL이 아닌 값을 반환하므로 A가 NULL이 아니면 A를 반환한다.\n\n**오답 풀이**\n- 1번: A가 NULL이 아니면 B와 무관하게 A를 반환한다.\n- 2번: A와 B가 NULL이면 세 번째 인자인 ''50''이 반환될 수 있다.\n- 3번: B가 NULL이면 50 * B도 NULL이므로 세 번째 인자로 넘어갈 수 있다.\n- 4번: COALESCE의 규칙에 맞다.\n\n**보충 개념**\nCOALESCE(expr1, expr2, ...)는 첫 번째 NULL이 아닌 표현식을 반환한다. 인자 간 데이터 타입 호환성도 고려해야 한다.',
   'COALESCE', 2, @mock_exam_id, 20, 'NONE', NULL, NOW(6), NOW(6)),
  (6, '다음 NATURAL JOIN 결과에 대한 설명으로 가장 적절한 것은?\n\n**<TAB_A>**\n| KEYA | COL1 | COL2 |\n|---:|---|---|\n| 1 | A | 가 |\n| 2 | A | 가 |\n| 5 | C | 다 |\n\n**<TAB_B>**\n| KEYB | COL1 | COL2 |\n|---:|---|---|\n| 1 | A | 가 |\n| 3 | C | 다 |\n\n```sql\nSELECT *\nFROM TAB_A NATURAL JOIN TAB_B;\n```\n\n① COL1, COL2가 모두 같은 행이 조인되어 3건이 출력된다.\n② KEYA와 KEYB가 같아야만 조인되므로 1건만 출력된다.\n③ NATURAL JOIN은 항상 카테시안 곱을 생성한다.\n④ 동일 이름 컬럼이 없어 오류가 발생한다.', 'MCQ', 1, '정답: 1. NATURAL JOIN은 두 테이블의 동일 이름 컬럼인 COL1, COL2를 자동으로 조인 조건으로 사용하므로 (A, 가) 2건과 (C, 다) 1건이 매칭되어 총 3건이 출력된다.\n\n**오답 풀이**\n- 1번: 동일 이름 컬럼 COL1, COL2 기준으로 3건이 조인된다.\n- 2번: KEYA와 KEYB는 이름이 다르므로 NATURAL JOIN 조건에 포함되지 않는다.\n- 3번: 카테시안 곱은 CROSS JOIN의 특징이다.\n- 4번: COL1, COL2라는 동일 이름 컬럼이 있다.\n\n**보충 개념**\nNATURAL JOIN은 동일 이름 컬럼을 모두 조인 조건으로 사용한다. 의도하지 않은 컬럼이 조건에 포함될 수 있으므로 실무에서는 주의가 필요하다.',
   'NATURAL JOIN', 3, @mock_exam_id, 21, 'NONE', NULL, NOW(6), NOW(6)),
  (6, 'INNER JOIN 결과에서 KIM이라는 이름이 중복으로 출력되는 상황에 대한 설명으로 가장 적절한 것은?\n\n① 조인 조건을 만족하는 행 조합이 여러 개이면 같은 값이 중복 출력될 수 있다.\n② INNER JOIN은 중복 행을 자동으로 제거한다.\n③ INNER JOIN은 항상 한 테이블의 행 수만큼만 출력된다.\n④ 중복 이름이 있으면 SQL은 반드시 오류가 발생한다.', 'MCQ', 1, '정답: 1. INNER JOIN은 조인 조건을 만족하는 행 조합을 모두 반환하므로 동일한 이름이 여러 행에서 매칭되면 중복 출력될 수 있다.\n\n**오답 풀이**\n- 1번: 조인 결과의 중복 발생 원인을 적절히 설명한다.\n- 2번: INNER JOIN은 DISTINCT가 없으면 중복을 제거하지 않는다.\n- 3번: 결과 행 수는 매칭 조합 수에 따라 달라진다.\n- 4번: 중복 이름 자체는 오류가 아니다.\n\n**보충 개념**\n조인 결과는 조건을 만족하는 행의 조합 수로 결정된다. 중복 제거가 필요하면 DISTINCT나 집계가 필요할 수 있다.',
   'INNER JOIN', 2, @mock_exam_id, 22, 'NONE', NULL, NOW(6), NOW(6)),
  (6, 'LEFT OUTER JOIN 결과로 SMITH 행의 오른쪽 테이블 컬럼이 NULL로 출력되었다. 이에 대한 설명으로 가장 적절한 것은?\n\n① SMITH 행은 왼쪽 테이블에는 존재하지만 오른쪽 테이블에는 조인 조건을 만족하는 행이 없다.\n② SMITH 행은 오른쪽 테이블에만 존재한다.\n③ LEFT OUTER JOIN에서는 매칭되지 않은 왼쪽 행이 모두 제거된다.\n④ NULL이 출력되면 SQL 문법 오류이다.', 'MCQ', 1, '정답: 1. LEFT OUTER JOIN은 왼쪽 테이블의 행을 보존하며, 오른쪽에 매칭 행이 없으면 오른쪽 컬럼을 NULL로 채운다.\n\n**오답 풀이**\n- 1번: LEFT OUTER JOIN의 미매칭 행 처리 방식이다.\n- 2번: 오른쪽 테이블에만 존재하는 행은 LEFT OUTER JOIN에서 기본적으로 보존되지 않는다.\n- 3번: LEFT OUTER JOIN은 왼쪽 행을 제거하지 않고 보존한다.\n- 4번: NULL 출력은 정상적인 외부 조인 결과이다.\n\n**보충 개념**\nLEFT OUTER JOIN은 왼쪽 테이블 기준으로 모든 행을 반환한다. 매칭되는 오른쪽 행이 없으면 오른쪽 컬럼 값은 NULL이 된다.',
   'LEFT OUTER JOIN', 2, @mock_exam_id, 23, 'NONE', NULL, NOW(6), NOW(6)),
  (6, '다음 보기 중 행의 수가 가장 많은 SQL은?\n\n**<TAB1>**\n| CODE | PCOLOR |\n|---:|---|\n| 1 | 빨강 |\n| 2 | 노랑 |\n| 3 | 파랑 |\n| 4 | 검정 |\n\n**<TAB2>**\n| CODE | PSIZE |\n|---:|---|\n| 1 | 소 |\n| 2 | 중 |\n| 3 | 대 |\n| 4 | 특대 |\n\n① SELECT CODE FROM TAB1 UNION ALL SELECT CODE FROM TAB2\n② SELECT * FROM TAB1 JOIN TAB2 ON TAB1.CODE = TAB2.CODE\n③ SELECT * FROM TAB1, TAB2 WHERE TAB1.PCOLOR IN (''노랑'',''파랑'',''검정'') AND TAB2.PSIZE IN (''소'',''중'',''대'')\n④ SELECT * FROM TAB1 FULL OUTER JOIN TAB2 ON TAB1.CODE = TAB2.CODE', 'MCQ', 3, '정답: 3. 3번은 TAB1에서 3행, TAB2에서 3행을 선택해 조인 조건 없이 조합을 만들므로 3×3=9행이 된다.\n\n**오답 풀이**\n- 1번: TAB1 4행과 TAB2 4행을 UNION ALL 하므로 8행이다.\n- 2번: CODE가 모두 1:1로 매칭되므로 INNER JOIN 결과는 4행이다.\n- 3번: 선택된 3행과 3행의 조합으로 9행이 되어 가장 많다.\n- 4번: CODE가 모두 매칭되므로 FULL OUTER JOIN 결과는 4행이다.\n\n**보충 개념**\nFROM 절에 여러 테이블을 나열하고 조인 조건이 없으면 카테시안 곱이 발생한다. 결과 행 수는 각 입력 행 수의 곱이다.',
   '카테시안 곱', 3, @mock_exam_id, 24, 'NONE', NULL, NOW(6), NOW(6)),
  (7, '제약 조건에 대한 설명으로 적절하지 않은 것은?\n\n① PK는 NOT NULL이다.\n② FK는 부모 테이블의 기본키 또는 고유키를 참조할 수 있다.\n③ UK는 항상 NOT NULL이다.\n④ CHECK는 특정 조건을 만족하는 값만 허용한다.', 'MCQ', 3, '정답: 3. UNIQUE 제약조건은 중복을 제한하지만 DBMS에 따라 NULL을 허용할 수 있으므로 항상 NOT NULL이라고 할 수 없다.\n\n**오답 풀이**\n- 1번: 기본키는 유일성과 NOT NULL을 만족한다.\n- 2번: 외래키는 부모 테이블의 기본키 또는 고유키를 참조할 수 있다.\n- 3번: UNIQUE가 항상 NOT NULL이라는 설명은 틀리다.\n- 4번: CHECK는 조건식을 통해 값의 범위를 제한한다.\n\n**보충 개념**\nPRIMARY KEY는 UNIQUE와 NOT NULL 성격을 모두 가진다. UNIQUE는 중복 방지 제약이지만 NULL 처리 방식은 DBMS별로 차이가 있다.',
   '제약조건', 2, @mock_exam_id, 25, 'NONE', NULL, NOW(6), NOW(6)),
  (6, '아래 SQL과 같은 결과를 반환하는 SQL로 가장 적절한 것은?\n\n```sql\nSELECT *\nFROM A\nWHERE 번호 IN (\n    SELECT 번호\n    FROM B\n    WHERE A.성별 = B.성별\n);\n```\n\n① SELECT * FROM A WHERE EXISTS (SELECT 1 FROM B WHERE A.성별 = B.성별 AND A.번호 = B.번호)\n② SELECT * FROM A JOIN B ON A.성별 = B.성별\n③ SELECT * FROM A WHERE A.성별 IN (SELECT B.성별 FROM B WHERE A.번호 = B.번호)\n④ SELECT * FROM A WHERE 번호 = ALL (SELECT 번호 FROM B WHERE A.성별 = B.성별)', 'MCQ', 1, '정답: 1. 원 SQL은 같은 성별의 B 행 중 A.번호와 같은 번호가 존재하는지 확인하므로 EXISTS에 성별과 번호 조건을 모두 넣은 1번과 같은 의미이다.\n\n**오답 풀이**\n- 1번: IN 조건을 EXISTS로 올바르게 변환한 형태이다.\n- 2번: 성별만 같으면 조인되어 번호 조건이 빠진다.\n- 3번: 성별 IN 조건으로 바뀌어 원문의 번호 포함 여부와 다르다.\n- 4번: ALL은 서브쿼리의 모든 번호와 같아야 하므로 의미가 다르다.\n\n**보충 개념**\nIN은 값이 서브쿼리 결과 집합에 포함되는지 확인한다. EXISTS로 바꿀 때는 동일한 비교 조건을 상관 조건으로 명확히 작성해야 한다.',
   'IN EXISTS', 3, @mock_exam_id, 26, 'NONE', NULL, NOW(6), NOW(6)),
  (6, '아래 SQL 결과로 알맞은 것은?\n\n**<TAB_A>**\n| COL1 |\n|---:|\n| 1 |\n| 2 |\n| NULL |\n\n**<TAB_B>**\n| COL2 |\n|---:|\n| 1 |\n| 2 |\n| 3 |\n\n```sql\nSELECT COUNT(*)\nFROM TAB_B\nWHERE COL2 NOT IN (SELECT COL1 FROM TAB_A);\n```\n\n① NULL\n② 0\n③ 1\n④ 전체 건수', 'MCQ', 2, '정답: 2. NOT IN의 목록에 NULL이 포함되면 비교 결과가 UNKNOWN이 되어 조건을 만족하는 행이 없어 COUNT(*) 결과는 0이다.\n\n**오답 풀이**\n- 1번: COUNT(*)는 결과 행이 없어도 NULL이 아니라 0을 반환한다.\n- 2번: NULL이 포함된 NOT IN 조건 때문에 반환 행이 없다.\n- 3번: 3은 1,2와 다르지만 NULL과의 비교 때문에 UNKNOWN이 되어 제외된다.\n- 4번: 전체 건수가 반환되지 않는다.\n\n**보충 개념**\n`NOT IN` 서브쿼리 결과에 NULL이 있으면 의도와 달리 결과가 없을 수 있다. NULL 가능성이 있으면 `NOT EXISTS`를 고려하는 것이 안전하다.',
   'NOT IN', 3, @mock_exam_id, 27, 'NONE', NULL, NOW(6), NOW(6)),
  (5, '아래 SQL 결과로 알맞은 것은?\n\n**<TAB>**\n| COL |\n|---|\n| A |\n| B |\n| C |\n| NULL |\n\n```sql\nSELECT *\nFROM TAB\nWHERE COL IN (''A'', ''B'', NULL);\n```\n\n① A, B, C, NULL\n② A, B\n③ A, B, NULL\n④ NULL', 'MCQ', 2, '정답: 2. IN 목록에 NULL이 포함되어도 `COL = NULL`은 TRUE가 되지 않으므로 A와 B만 조회된다.\n\n**오답 풀이**\n- 1번: C와 NULL은 조건을 만족하지 않는다.\n- 2번: A와 B만 IN 목록의 실제 값과 일치한다.\n- 3번: NULL은 `IN (..., NULL)`로 조회되지 않는다.\n- 4번: NULL만 조회되지 않는다.\n\n**보충 개념**\nNULL 값을 조회하려면 `COL IS NULL` 조건을 별도로 사용해야 한다. `IN (''A'',''B'',NULL)`은 `COL=''A'' OR COL=''B'' OR COL=NULL`과 유사하게 동작한다.',
   'IN NULL', 2, @mock_exam_id, 28, 'NONE', NULL, NOW(6), NOW(6)),
  (5, '아래 SQL 결과로 알맞은 것은?\n\n**<TAB>**\n| 나이_그룹 | 나이 |\n|---:|---:|\n| 1 | 10 |\n| 1 | 10 |\n| 2 | 20 |\n| 2 | 20 |\n| 3 | 30 |\n| 3 | 30 |\n| 3 | NULL |\n\n```sql\nSELECT AVG(나이) AS 평균_나이\nFROM TAB\nGROUP BY 나이_그룹;\n```\n\n① 10, 20, 25\n② 10, 20, NULL\n③ 10, 20, 30\n④ 10, 20, 20', 'MCQ', 3, '정답: 3. AVG는 NULL을 제외하고 평균을 계산하므로 그룹 1은 10, 그룹 2는 20, 그룹 3은 30이다.\n\n**오답 풀이**\n- 1번: NULL을 0으로 포함하여 평균을 낸 값과 혼동한 것이다.\n- 2번: 그룹 3에는 NULL이 아닌 30 값이 있으므로 NULL이 아니다.\n- 3번: NULL을 제외한 평균 계산 결과이다.\n- 4번: 그룹 3의 평균을 잘못 계산했다.\n\n**보충 개념**\nAVG, SUM, MIN, MAX 등 대부분의 집계 함수는 NULL을 제외한다. COUNT(*)는 NULL 여부와 관계없이 행 수를 센다.',
   'AVG', 2, @mock_exam_id, 29, 'NONE', NULL, NOW(6), NOW(6)),
  (6, '아래 결과를 출력하기 위한 GROUPING SETS 절로 가장 적절한 것은?\n\n**<조건>**\n- 상세 집계: COL1, COL2별 집계\n- 추가 집계: COL2별 집계만 출력\n- COL1만 기준인 소계는 출력하지 않는다.\n\n① GROUP BY GROUPING SETS ((COL1, COL2), (COL2))\n② GROUP BY ROLLUP (COL1, COL2)\n③ GROUP BY CUBE (COL1, COL2)\n④ GROUP BY GROUPING SETS ((COL1), ())', 'MCQ', 1, '정답: 1. (COL1, COL2) 상세 집계와 (COL2) 집계만 필요하므로 GROUPING SETS((COL1, COL2), (COL2))가 적절하다.\n\n**오답 풀이**\n- 1번: 필요한 두 그룹 집합만 정확히 지정한다.\n- 2번: ROLLUP(COL1, COL2)는 (COL1), ()도 생성한다.\n- 3번: CUBE는 모든 조합의 소계를 생성한다.\n- 4번: 필요한 (COL1, COL2), (COL2)가 없다.\n\n**보충 개념**\nGROUPING SETS는 원하는 그룹 조합을 직접 지정할 수 있다. ROLLUP과 CUBE보다 필요한 소계만 선택적으로 만들 때 유용하다.',
   'GROUPING SETS', 3, @mock_exam_id, 30, 'NONE', NULL, NOW(6), NOW(6)),
  (6, '아래 Window Function 설명에 맞는 것은?\n\n**<지문>**\n파티션별 윈도우의 전체 건수에서 현재 행보다 작거나 같은 건수에 대한 누적 백분율을 구하는 함수\n\n① CUME_DIST\n② DENSE_RANK\n③ RANK\n④ PERCENT_RANK', 'MCQ', 1, '정답: 1. CUME_DIST는 현재 행보다 작거나 같은 행의 누적 분포 비율을 반환한다.\n\n**오답 풀이**\n- 1번: 누적 분포 비율을 구하는 함수이다.\n- 2번: DENSE_RANK는 동점 후 순위를 건너뛰지 않는 순위 함수이다.\n- 3번: RANK는 동점 후 순위를 건너뛰는 순위 함수이다.\n- 4번: PERCENT_RANK는 상대 순위를 0~1 범위로 반환한다.\n\n**보충 개념**\n분포 함수에는 CUME_DIST, PERCENT_RANK, NTILE, RATIO_TO_REPORT 등이 있다. CUME_DIST는 누적 분포, PERCENT_RANK는 상대 순위를 계산한다.',
   'CUME_DIST', 2, @mock_exam_id, 31, 'NONE', NULL, NOW(6), NOW(6)),
  (6, '아래 설명을 만족하는 SQL로 알맞은 것은?\n\n**<지문>**\n부서별로 연봉을 오름차순 정렬하고, 현재 연봉 기준 -100부터 +200 사이의 연봉자 수를 구한다.\n\n① SELECT emp_id, salary, COUNT(*) OVER (PARTITION BY dep_id ORDER BY salary ROWS BETWEEN 100 PRECEDING AND 200 FOLLOWING) AS salary_count FROM emp\n② SELECT emp_id, salary, COUNT(*) OVER (PARTITION BY dep_id ORDER BY salary RANGE BETWEEN 100 PRECEDING AND 200 FOLLOWING) AS salary_count FROM emp\n③ SELECT emp_id, salary, COUNT(*) OVER (PARTITION BY dep_id) AS salary_count FROM emp\n④ SELECT emp_id, salary, COUNT(*) OVER (ORDER BY salary RANGE BETWEEN 100 PRECEDING AND 200 FOLLOWING) AS salary_count FROM emp', 'MCQ', 2, '정답: 2. 연봉 값의 범위 -100부터 +200 사이를 기준으로 세야 하므로 ROWS가 아니라 RANGE를 사용하고, 부서별 계산을 위해 PARTITION BY dep_id가 필요하다.\n\n**오답 풀이**\n- 1번: ROWS는 물리적 행 수 기준이므로 연봉 값 범위 조건에 맞지 않는다.\n- 2번: 부서별 파티션과 연봉 값 범위 프레임을 올바르게 사용했다.\n- 3번: 부서 전체 건수만 계산하고 연봉 범위를 반영하지 않는다.\n- 4번: 부서별 파티션이 없어 전체 기준으로 계산된다.\n\n**보충 개념**\nROWS는 행 개수 기준, RANGE는 ORDER BY 값의 논리적 범위 기준이다. 급여 ± 범위 같은 문제는 RANGE 프레임을 사용한다.',
   '윈도우 프레임', 4, @mock_exam_id, 32, 'NONE', NULL, NOW(6), NOW(6)),
  (6, '아래 SQL에서 EMPLOYEE_ID가 7780인 행의 결과로 알맞은 것은?\n\n**<TAB>**\n| EMPLOYEE_ID | SALARY |\n|---:|---:|\n| 7780 | 4000 |\n| 7781 | 4000 |\n| 7782 | 3000 |\n| 7783 | 3000 |\n| 7784 | 2000 |\n\n```sql\nSELECT EMPLOYEE_ID,\n       ROW_NUMBER() OVER (ORDER BY SALARY, EMPLOYEE_ID) AS ROW_NUM,\n       RANK() OVER (ORDER BY SALARY) AS RANK_NUM,\n       DENSE_RANK() OVER (ORDER BY SALARY) AS DENSE_RANK_NUM\nFROM EMPLOYEES;\n```\n\n① 4, 4, 3\n② 3, 3, 3\n③ 4, 4, 4\n④ 3, 4, 3', 'MCQ', 1, '정답: 1. SALARY 오름차순에서 2000이 1번째, 3000 두 행이 2~3번째, 4000 두 행이 4~5번째이다. ROW_NUMBER는 SALARY, EMPLOYEE_ID 기준으로 정렬하므로 7780은 4000 그룹의 첫 번째가 되어 ROW_NUMBER 4, RANK 4, DENSE_RANK 3이다.\n\n**오답 풀이**\n- 1번: ROW_NUMBER 4, RANK 4, DENSE_RANK 3으로 맞다.\n- 2번: RANK가 3이 될 수 없다.\n- 3번: DENSE_RANK는 4000을 세 번째 distinct 값으로 보므로 3이다.\n- 4번: ROW_NUMBER가 3이 될 수 없다.\n\n**보충 개념**\nROW_NUMBER는 행마다 고유 번호를 부여한다. RANK는 동점 이후 순위를 건너뛰고, DENSE_RANK는 동점 이후 순위를 건너뛰지 않는다. ROW_NUMBER는 동점이 있으면 추가 정렬 기준을 명시해야 결과가 안정적이다.',
   '순위 함수', 4, @mock_exam_id, 33, 'NONE', NULL, NOW(6), NOW(6)),
  (5, '강좌번호가 100, 101인 과목을 동시에 듣는 학번을 구하는 SQL로 알맞은 것은?\n\n① SELECT 학번 FROM 수강 WHERE 강좌번호 = 100 AND 강좌번호 = 101\n② SELECT 학번 FROM 수강 WHERE 강좌번호 = 100 INTERSECT SELECT 학번 FROM 수강 WHERE 강좌번호 = 101\n③ SELECT 학번 FROM 수강 WHERE 강좌번호 IN (100, 101)\n④ SELECT 학번 FROM 수강 WHERE 강좌번호 = 100 OR 101', 'MCQ', 2, '정답: 2. 100번 강좌를 듣는 학번 집합과 101번 강좌를 듣는 학번 집합의 교집합을 구해야 하므로 INTERSECT가 적절하다.\n\n**오답 풀이**\n- 1번: 한 행의 강좌번호가 동시에 100이면서 101일 수 없다.\n- 2번: 두 강좌를 모두 듣는 학번을 교집합으로 구한다.\n- 3번: 둘 중 하나만 듣는 학번도 포함된다.\n- 4번: `OR 101`은 올바른 조건식이 아니다.\n\n**보충 개념**\n동시에 만족해야 하는 조건이 서로 다른 행에 나뉘어 존재할 때는 INTERSECT, GROUP BY HAVING COUNT, 셀프 조인 등을 사용할 수 있다.',
   'INTERSECT', 3, @mock_exam_id, 34, 'NONE', NULL, NOW(6), NOW(6)),
  (6, '아래 결과를 출력하는 SQL의 빈칸에 적절한 것은?\n\n**<SQL>**\n```sql\nSELECT 이름,\n       점수,\n       (SELECT ( 1 )\n        FROM 점수테이블 T2\n        WHERE ( 2 )) AS 순위\nFROM 점수테이블 T1\nORDER BY 순위;\n```\n\n**<조건>**\n자기보다 점수가 높은 행의 개수에 1을 더해 등수를 구한다.\n\n① (1) COUNT(*) + 1, (2) T1.점수 < T2.점수\n② (1) COUNT(*), (2) T1.점수 = T2.점수\n③ (1) RANK() + 1, (2) T1.점수 > T2.점수\n④ (1) SUM(점수), (2) T1.점수 < T2.점수', 'MCQ', 1, '정답: 1. 자신보다 점수가 높은 행의 개수를 세고 1을 더하면 등수를 구할 수 있으므로 `COUNT(*) + 1`과 `T1.점수 < T2.점수`가 적절하다.\n\n**오답 풀이**\n- 1번: 자기보다 높은 점수의 개수 + 1로 순위를 구한다.\n- 2번: 같은 점수의 개수를 세므로 순위가 아니다.\n- 3번: 서브쿼리 내부에서 RANK()를 그렇게 사용할 수 없다.\n- 4번: 점수 합계를 구하는 식으로 순위 계산과 다르다.\n\n**보충 개념**\n셀프 조인 또는 상관 서브쿼리로 순위를 계산할 수 있다. 현재 행보다 큰 값의 개수에 1을 더하면 내림차순 기준 순위가 된다.',
   '셀프 조인', 3, @mock_exam_id, 35, 'NONE', NULL, NOW(6), NOW(6)),
  (5, '행이 2건인 테이블에서 결과가 다른 SQL은?\n\n① SELECT * FROM T WHERE ROWNUM <= 1\n② SELECT * FROM T WHERE ROWNUM < 2\n③ SELECT * FROM T WHERE ROWNUM = 1\n④ SELECT * FROM T WHERE ROWNUM = 2', 'MCQ', 4, '정답: 4. Oracle에서 ROWNUM은 반환되는 첫 행부터 1이 부여되므로 `ROWNUM = 2` 조건은 첫 행이 통과하지 못해 결과가 나오지 않는다.\n\n**오답 풀이**\n- 1번: 첫 번째 행 1건이 반환된다.\n- 2번: ROWNUM < 2는 첫 번째 행 1건이 반환된다.\n- 3번: ROWNUM = 1은 첫 번째 행 1건이 반환된다.\n- 4번: ROWNUM = 2는 일반적으로 0건이 된다.\n\n**보충 개념**\nROWNUM은 WHERE 조건을 통과하며 반환되는 순서대로 부여된다. N번째 이후 행을 구하려면 인라인 뷰에서 ROWNUM을 먼저 부여한 뒤 바깥 쿼리에서 필터링해야 한다.',
   'ROWNUM', 3, @mock_exam_id, 36, 'NONE', NULL, NOW(6), NOW(6)),
  (7, '아래 UPDATE 구문에 대한 설명으로 알맞은 것은?\n\n```sql\nUPDATE emp_test A\nSET salary = (\n    SELECT salary * 1.1\n    FROM emp_test B\n    WHERE A.employee_id = B.employee_id\n      AND B.department_id = 60\n);\n```\n\n**<조건>**\nUPDATE 문에는 별도의 WHERE 절이 없다.\n\n① DEPTNO가 10인 사원들의 월급을 10% 인상하는 쿼리이다.\n② UPDATE ... WHERE DEPTNO = 10과 동일한 의미이다.\n③ 오류가 발생한다.\n④ department_id가 60이 아닌 모든 사원들의 salary가 NULL로 수정된다.', 'MCQ', 4, '정답: 4. UPDATE 문 자체에 WHERE 절이 없으므로 모든 행이 갱신 대상이며, 상관 서브쿼리가 department_id=60 조건을 만족하지 않는 행은 NULL을 반환하여 salary가 NULL로 갱신될 수 있다.\n\n**오답 풀이**\n- 1번: department_id=60 조건이며, 전체 UPDATE 대상 제한 조건이 아니다.\n- 2번: UPDATE 문에 WHERE가 없으므로 department_id=60 행만 갱신하는 것과 다르다.\n- 3번: 스칼라 서브쿼리 결과가 없으면 NULL로 처리될 수 있어 문법 오류는 아니다.\n- 4번: 조건에 맞지 않는 행의 salary가 NULL로 바뀔 수 있다.\n\n**보충 개념**\nUPDATE의 SET 절에 서브쿼리를 사용할 때는 UPDATE 대상 행을 제한하는 WHERE 절을 별도로 작성해야 한다. 그렇지 않으면 의도하지 않은 행까지 갱신될 수 있다.',
   'UPDATE', 4, @mock_exam_id, 37, 'NONE', NULL, NOW(6), NOW(6)),
  (7, '아래 TABLE에 대한 SQL 수행 후 최종 SUM(COL1) 결과로 가장 적절한 것은?\n\n**<TABLE>**\n- COL1: PRIMARY KEY\n- COL2: CHECK (COL2 > 500)\n\n**<SQL>**\n```sql\nINSERT INTO T VALUES (500, 600);\nUPDATE T SET COL2 = 400 WHERE COL1 = 500;\nINSERT INTO T VALUES (500, 700);\nINSERT INTO T VALUES (270, 800);\nSELECT SUM(COL1) FROM T;\n```\n\n① 770\n② 500\n③ 0\n④ 오류로 인해 모든 작업이 취소된다.', 'MCQ', 1, '정답: 1. 첫 번째 INSERT는 정상 수행되어 COL1=500 행이 저장된다. UPDATE는 COL2를 400으로 바꾸려 하므로 CHECK(COL2 > 500)를 위반해 실패한다. 두 번째 INSERT는 COL1=500이 이미 존재하므로 PRIMARY KEY를 위반해 실패한다. 마지막 INSERT는 정상 수행되어 COL1=270 행이 추가된다. 따라서 최종 SUM(COL1)은 500 + 270 = 770이다.\n\n**오답 풀이**\n- 1번: 정상 반영된 COL1 값 500과 270의 합이다.\n- 2번: 마지막 정상 INSERT를 누락한 값이다.\n- 3번: 정상 INSERT가 모두 취소되는 상황이 아니다.\n- 4번: 개별 DML 오류가 이전의 정상 수행 DML을 자동으로 모두 취소한다고 볼 수 없다.\n\n**보충 개념**\n제약조건을 위반한 DML은 실패하며 해당 변경은 반영되지 않는다. 이전에 정상 수행된 문장까지 자동으로 모두 취소되는 것은 아니다.',
   '제약조건', 4, @mock_exam_id, 38, 'NONE', NULL, NOW(6), NOW(6)),
  (6, '아래 SQL 결과로 알맞은 것은?\n\n```sql\nSELECT COL1,\n       SUM(매출) AS 총매출\nFROM 매출테이블\nGROUP BY COL1\nORDER BY 총매출;\n```\n\n**<조건>**\n부서1의 총매출은 18000이고, 부서2의 총매출은 11300이다.\n\n① 부서1 18000, 부서2 11300\n② 부서2 11300, 부서1 18000\n③ 부서1 11300, 부서2 18000\n④ 정렬 순서는 보장되지 않는다.', 'MCQ', 2, '정답: 2. ORDER BY 총매출은 기본 오름차순이므로 총매출이 작은 부서2 11300이 먼저 출력되고, 부서1 18000이 다음에 출력된다.\n\n**오답 풀이**\n- 1번: 총매출 내림차순 결과이다.\n- 2번: 총매출 오름차순 정렬 결과이다.\n- 3번: 부서별 총매출 값이 서로 바뀌었다.\n- 4번: ORDER BY가 있으므로 정렬 기준이 있다.\n\n**보충 개념**\nORDER BY에서 정렬 방향을 생략하면 기본값은 ASC이다. 별칭으로 지정한 집계 컬럼을 ORDER BY에서 사용할 수 있다.',
   'ORDER BY', 2, @mock_exam_id, 39, 'NONE', NULL, NOW(6), NOW(6)),
  (5, '아래 SQL에 대한 결과로 알맞은 것은?\n\n```sql\nSELECT COL1,\n       MIN(COL2),\n       MAX(COL2),\n       SUM(COL2 + COL3)\nFROM T\nGROUP BY COL1;\n```\n\n**<조건>**\nCOL1이 NULL인 그룹에서는 COL2와 COL3 값이 모두 NULL이다.\n\n① COL1이 NULL인 그룹의 MIN, MAX, SUM 결과는 모두 NULL이다.\n② COL1이 NULL인 그룹의 MIN, MAX, SUM 결과는 모두 0이다.\n③ COL1이 NULL인 그룹은 GROUP BY 결과에서 제외된다.\n④ SUM(COL2 + COL3)은 NULL을 0으로 자동 변환하여 계산한다.', 'MCQ', 1, '정답: 1. 그룹 내 집계 대상 값이 모두 NULL이면 MIN, MAX, SUM 결과는 NULL이 된다.\n\n**오답 풀이**\n- 1번: 모든 집계 대상이 NULL인 경우의 결과로 적절하다.\n- 2번: 집계 함수는 NULL을 자동으로 0으로 바꾸지 않는다.\n- 3번: GROUP BY에서 NULL은 하나의 그룹으로 묶일 수 있다.\n- 4번: NULL이 포함된 산술 연산은 NULL이 된다.\n\n**보충 개념**\n집계 함수는 NULL을 제외하지만, 집계할 값이 모두 NULL이면 SUM, MIN, MAX는 NULL을 반환할 수 있다. COUNT는 대상에 따라 0을 반환할 수 있다.',
   'NULL 집계', 3, @mock_exam_id, 40, 'NONE', NULL, NOW(6), NOW(6)),
  (7, '아래 빈칸에 알맞은 명령어는?\n\n**<지문>**\n입력, 수정, 삭제한 데이터에 대해 전혀 문제가 없다고 판단됐을 경우 (  ) 명령어로 트랜잭션을 완료할 수 있다.\n\n① COMMIT\n② ROLLBACK\n③ SAVEPOINT\n④ REVOKE', 'MCQ', 1, '정답: 1. COMMIT은 트랜잭션의 변경 내용을 확정하고 영구 반영하는 명령어이다.\n\n**오답 풀이**\n- 1번: 트랜잭션을 완료하고 변경 내용을 확정한다.\n- 2번: ROLLBACK은 변경 내용을 취소한다.\n- 3번: SAVEPOINT는 트랜잭션 중간 저장점을 만든다.\n- 4번: REVOKE는 권한 회수 명령이다.\n\n**보충 개념**\nTCL에는 COMMIT, ROLLBACK, SAVEPOINT 등이 있다. COMMIT 이후에는 일반적으로 해당 변경을 ROLLBACK으로 되돌릴 수 없다.',
   'COMMIT', 1, @mock_exam_id, 41, 'NONE', NULL, NOW(6), NOW(6)),
  (6, '아래 SQL에 대한 설명으로 적절한 것은?\n\n```sql\nSELECT 주문번호, 계좌번호\nFROM 주문\n     JOIN 주문내역 ON 주문.주문번호 = 주문내역.주문번호\nORDER BY 계좌번호 DESC;\n```\n\n① 계좌번호를 오름차순으로 정렬한다.\n② 계좌번호를 내림차순으로 정렬한다.\n③ ORDER BY 절이 있으므로 조인이 수행되지 않는다.\n④ DESC는 NULL을 제외하는 조건이다.', 'MCQ', 2, '정답: 2. ORDER BY 계좌번호 DESC는 계좌번호를 내림차순으로 정렬한다.\n\n**오답 풀이**\n- 1번: 오름차순은 ASC 또는 정렬 방향 생략 시 기본값이다.\n- 2번: DESC는 내림차순 정렬을 의미한다.\n- 3번: ORDER BY는 조인 결과를 정렬하는 절이다.\n- 4번: DESC는 NULL 제외 조건이 아니다.\n\n**보충 개념**\nORDER BY는 SELECT 결과의 출력 순서를 결정한다. ASC는 오름차순, DESC는 내림차순이다.',
   'ORDER BY', 1, @mock_exam_id, 42, 'NONE', NULL, NOW(6), NOW(6)),
  (7, '테이블의 데이터와 종속된 테이블을 지우는 명령어로 알맞은 것은?\n\n① TRUNCATE\n② DROP CASCADE\n③ DELETE\n④ ALTER', 'MCQ', 2, '정답: 2. DROP CASCADE는 객체 삭제 시 종속된 객체까지 함께 삭제하는 옵션으로 사용할 수 있다.\n\n**오답 풀이**\n- 1번: TRUNCATE는 테이블 데이터만 빠르게 삭제하고 구조는 유지한다.\n- 2번: 종속 객체까지 함께 제거하는 의미에 가장 적절하다.\n- 3번: DELETE는 행 데이터를 삭제하는 DML이다.\n- 4번: ALTER는 객체 구조 변경 명령이다.\n\n**보충 개념**\nDROP은 객체 자체를 삭제한다. CASCADE 옵션은 종속된 제약조건이나 객체까지 함께 제거할 때 사용된다.',
   'DROP CASCADE', 2, @mock_exam_id, 43, 'NONE', NULL, NOW(6), NOW(6)),
  (5, '아래 SQL에 대한 결과로 알맞은 것은?\n\n```sql\nSELECT CASE\n         WHEN 상품구분 = ''A'' THEN ''취급''\n         WHEN 상품구분 = ''B'' THEN ''보류''\n         ELSE ''취급안함''\n       END AS 처리결과\nFROM 상품;\n```\n\n상품구분이 ''C''인 행의 처리결과는?\n\n① 취급\n② 보류\n③ 취급안함\n④ NULL', 'MCQ', 3, '정답: 3. CASE 조건 중 상품구분=''C''에 해당하는 WHEN이 없으므로 ELSE 절의 ''취급안함''이 반환된다.\n\n**오답 풀이**\n- 1번: ''A''일 때 반환되는 값이다.\n- 2번: ''B''일 때 반환되는 값이다.\n- 3번: 조건에 해당하지 않으므로 ELSE 값이 반환된다.\n- 4번: ELSE가 있으므로 NULL이 아니라 ''취급안함''이다.\n\n**보충 개념**\nCASE 표현식은 조건을 위에서부터 평가하고 처음 TRUE인 결과를 반환한다. 일치하는 WHEN이 없고 ELSE가 있으면 ELSE 값을 반환한다.',
   'CASE', 1, @mock_exam_id, 44, 'NONE', NULL, NOW(6), NOW(6)),
  (5, '아래 SQL에 대한 설명으로 알맞은 것은?\n\n```sql\nSELECT *\nFROM T\nWHERE COL1 LIKE ''A%'';\n```\n\n① COL1이 대문자 A로 시작하는 모든 행을 조회한다.\n② COL1이 A로 끝나는 모든 행을 조회한다.\n③ COL1에 A가 포함되지 않은 행을 조회한다.\n④ COL1의 두 번째 문자가 A인 행을 조회한다.', 'MCQ', 1, '정답: 1. LIKE ''A%''는 A로 시작하고 뒤에 임의의 문자열이 오는 값을 찾는다.\n\n**오답 풀이**\n- 1번: A로 시작하는 값 조건이다.\n- 2번: A로 끝나는 조건은 ''%A''이다.\n- 3번: A가 포함되지 않는 조건은 NOT LIKE ''%A%''와 가깝다.\n- 4번: 두 번째 문자가 A인 조건은 ''_A%''이다.\n\n**보충 개념**\nLIKE에서 %는 0개 이상의 임의 문자열을 의미하고, _는 정확히 한 글자를 의미한다.',
   'LIKE', 1, @mock_exam_id, 45, 'NONE', NULL, NOW(6), NOW(6)),
  (6, '아래 SQL 결과를 출력하는 SQL로 알맞은 것은?\n\n**<DATA>**\n| COL1 | COL2 |\n|---:|---:|\n| 1 | NULL |\n| 2 | 1 |\n| 3 | 2 |\n\n**<조건>**\nCOL1 기준으로 정렬했을 때 이전 행의 COL1 값을 COL2처럼 출력한다.\n\n① SELECT COL1, LAG(COL1) OVER (ORDER BY COL1) AS COL2 FROM T\n② SELECT COL1, LEAD(COL1) OVER (ORDER BY COL1) AS COL2 FROM T\n③ SELECT COL1, FIRST_VALUE(COL1) OVER (ORDER BY COL1) AS COL2 FROM T\n④ SELECT COL1, ROW_NUMBER() OVER (ORDER BY COL1) AS COL2 FROM T', 'MCQ', 1, '정답: 1. LAG는 현재 행 기준 이전 행의 값을 가져오므로 COL1이 1일 때 NULL, 2일 때 1, 3일 때 2를 반환한다.\n\n**오답 풀이**\n- 1번: 이전 행 값을 가져오는 LAG 사용이 적절하다.\n- 2번: LEAD는 다음 행 값을 가져온다.\n- 3번: FIRST_VALUE는 윈도우의 첫 번째 값을 반환한다.\n- 4번: ROW_NUMBER는 행 번호를 반환한다.\n\n**보충 개념**\nLAG는 이전 행, LEAD는 다음 행의 값을 참조하는 윈도우 함수이다. 시계열 비교나 이전 값 대비 변화량 계산에 자주 사용된다.',
   'LAG', 2, @mock_exam_id, 46, 'NONE', NULL, NOW(6), NOW(6)),
  (5, '아래 SQL의 결과로 알맞은 것은?\n\n```sql\nSELECT COUNT(*) + COUNT(col1) + COUNT(DISTINCT col2) AS RESULT\nFROM T;\n```\n\n**<조건>**\n- 전체 행 수는 5건이다.\n- col1이 NULL이 아닌 행 수는 3건이다.\n- col2의 중복 제거 후 NULL이 아닌 값의 수는 2건이다.\n\n① 5\n② 8\n③ 10\n④ 12', 'MCQ', 3, '정답: 3. COUNT(*)는 5, COUNT(col1)은 3, COUNT(DISTINCT col2)는 2이므로 합계는 10이다.\n\n**오답 풀이**\n- 1번: COUNT(*)만 계산한 값이다.\n- 2번: COUNT(DISTINCT col2)를 누락한 값이다.\n- 3번: 5 + 3 + 2 = 10으로 맞다.\n- 4번: NULL 또는 중복 값을 잘못 포함한 값이다.\n\n**보충 개념**\nCOUNT(*)는 전체 행 수를 센다. COUNT(컬럼)은 NULL이 아닌 값만 세고, COUNT(DISTINCT 컬럼)은 NULL을 제외하고 중복을 제거한 개수를 센다.',
   'COUNT', 2, @mock_exam_id, 47, 'NONE', NULL, NOW(6), NOW(6)),
  (5, '단일행 함수에 대한 설명으로 적절하지 않은 것은?\n\n① 각 행에 개별적으로 적용된다.\n② 여러 인자를 넣을 수 있다.\n③ 중첩 사용이 가능하다.\n④ GROUP BY 절에는 사용할 수 없다.', 'MCQ', 4, '정답: 4. 단일행 함수는 SELECT, WHERE, ORDER BY뿐 아니라 GROUP BY 절에서도 사용할 수 있다.\n\n**오답 풀이**\n- 1번: 단일행 함수는 각 행에 대해 개별적으로 작동한다.\n- 2번: 함수에 따라 여러 인자를 받을 수 있다.\n- 3번: 함수의 인자로 다른 함수를 넣는 중첩 사용이 가능하다.\n- 4번: GROUP BY 절에 사용할 수 없다는 설명은 틀리다.\n\n**보충 개념**\n단일행 함수는 각 행마다 하나의 결과를 반환한다. 예를 들어 `GROUP BY SUBSTR(name, 1, 3)`처럼 함수 표현식을 그룹 기준으로 사용할 수 있다.',
   '단일행 함수', 2, @mock_exam_id, 48, 'NONE', NULL, NOW(6), NOW(6)),
  (6, 'INNER JOIN에 대한 설명 중 적절하지 않은 것은?\n\n① 조인 조건을 만족하는 행만 결과에 포함한다.\n② ON 절을 사용하여 조인 조건을 명시할 수 있다.\n③ 조인으로 사용되는 컬럼은 컬럼명이 반드시 같아야 한다.\n④ 조인 조건이 같음 비교이면 등가 조인으로 볼 수 있다.', 'MCQ', 3, '정답: 3. INNER JOIN에서 조인 컬럼의 이름이 반드시 같을 필요는 없으며 ON 절에서 서로 다른 이름의 컬럼도 조건으로 연결할 수 있다.\n\n**오답 풀이**\n- 1번: INNER JOIN은 조건을 만족하는 행만 반환한다.\n- 2번: ON 절로 조인 조건을 작성할 수 있다.\n- 3번: 컬럼명이 반드시 같아야 한다는 설명은 틀리다.\n- 4번: 같은 값 비교 조건이면 등가 조인이다.\n\n**보충 개념**\nUSING이나 NATURAL JOIN은 동일 이름 컬럼을 전제로 하지만, ON 절을 사용하는 일반 INNER JOIN은 컬럼명이 달라도 조인할 수 있다.',
   'INNER JOIN', 2, @mock_exam_id, 49, 'NONE', NULL, NOW(6), NOW(6)),
  (6, '아래 SQL에 대한 결과로 알맞은 것은?\n\n**<T1>**\n| col1 | col2 | col3 |\n|---|---|---:|\n| 가 | A | 2 |\n| 나 | B | 3 |\n| 다 | C | NULL |\n\n**<T2>**\n| col1 | col2 |\n|---:|---|\n| 2 | A |\n| 3 | C |\n\n```sql\nSELECT *\nFROM T1 INNER JOIN T2 ON T1.COL2 = T2.COL2\nWHERE 1 = 1\n  AND T1.COL3 >= 3\n  AND T2.COL2 IN (''A'', ''B'');\n```\n\n① 결과 없음\n② 가\n③ 나\n④ 다', 'MCQ', 1, '정답: 1. 조인 조건 T1.COL2 = T2.COL2를 만족하는 것은 A와 C이다. A 행은 T1.COL3이 2라서 `>= 3`을 만족하지 못하고, C 행은 COL3이 NULL이며 T2.COL2 IN (''A'',''B'')도 만족하지 못하므로 최종 결과가 없다.\n\n**오답 풀이**\n- 1번: 모든 조건을 동시에 만족하는 행이 없다.\n- 2번: 가 행은 조인은 되지만 COL3 >= 3 조건을 만족하지 않는다.\n- 3번: 나 행은 T2에 COL2=''B''가 없어 조인되지 않는다.\n- 4번: 다 행은 COL3이 NULL이고 T2.COL2가 C라 조건을 만족하지 않는다.',
   'INNER JOIN', 3, @mock_exam_id, 50, 'NONE', NULL, NOW(6), NOW(6))
;